import{_ as e,o as a,c as i,ao as d}from"./chunks/framework.BKHFW9K8.js";const y=JSON.parse('{"title":"Capability parity with gllvmTMB","description":"","frontmatter":{},"headers":[],"relativePath":"gllvmtmb-parity.md","filePath":"gllvmtmb-parity.md","lastUpdated":null}'),l={name:"gllvmtmb-parity.md"};function r(n,t,o,s,c,g){return a(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="Capability-parity-with-gllvmTMB" tabindex="-1">Capability parity with gllvmTMB <a class="header-anchor" href="#Capability-parity-with-gllvmTMB" aria-label="Permalink to &quot;Capability parity with gllvmTMB {#Capability-parity-with-gllvmTMB}&quot;">​</a></h1><p>GLLVM.jl is a from-scratch Julia twin of R&#39;s <code>gllvmTMB</code>, built for fitting speed at moderate-to-large species counts while reproducing point estimates and likelihoods to machine precision on the shared Gaussian + phylogenetic path. This page is the live <strong>catch-up scoreboard</strong> — where GLLVM.jl stands against the <code>gllvmTMB</code> feature set. For <em>speed</em> comparisons see <a href="./comparison">Comparison</a> and <a href="./benchmarks">Benchmarks</a>.</p><p>Legend: ✅ available · 🔨 in progress · ⬜ planned · ⚡ GLLVM.jl advantage.</p><h2 id="Response-families" tabindex="-1">Response families <a class="header-anchor" href="#Response-families" aria-label="Permalink to &quot;Response families {#Response-families}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Family</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Gaussian</td><td style="text-align:center;">✅</td><td style="text-align:right;">closed-form marginal</td></tr><tr><td style="text-align:right;">Binomial (Bernoulli / counts)</td><td style="text-align:center;">✅</td><td style="text-align:right;">logit / probit / cloglog</td></tr><tr><td style="text-align:right;">Poisson</td><td style="text-align:center;">✅</td><td style="text-align:right;">log link</td></tr><tr><td style="text-align:right;">Negative binomial</td><td style="text-align:center;">✅</td><td style="text-align:right;">dispersion <code>r</code> jointly estimated</td></tr><tr><td style="text-align:right;">Beta</td><td style="text-align:center;">✅</td><td style="text-align:right;">precision <code>φ</code></td></tr><tr><td style="text-align:right;">Ordinal (cumulative logit)</td><td style="text-align:center;">✅</td><td style="text-align:right;">common ordered cutpoints</td></tr><tr><td style="text-align:right;">Gamma</td><td style="text-align:center;">✅</td><td style="text-align:right;">shape <code>α</code></td></tr><tr><td style="text-align:right;">Delta-lognormal</td><td style="text-align:center;">✅</td><td style="text-align:right;">first two-part family; shared 2-block Laplace substrate</td></tr><tr><td style="text-align:right;">Delta-Gamma</td><td style="text-align:center;">✅</td><td style="text-align:right;">occurrence Bernoulli × positive Gamma (log-link mean) on the substrate</td></tr><tr><td style="text-align:right;">Hurdle (Poisson / NB)</td><td style="text-align:center;">✅</td><td style="text-align:right;">occurrence Bernoulli × zero-truncated Poisson / NB2</td></tr><tr><td style="text-align:right;">Zero-inflated (ZIP / ZINB / ZIB)</td><td style="text-align:center;">✅</td><td style="text-align:right;">structural zero × Poisson / NB2 / Binomial; zero-inflation intercept-only (Λ_z = 0) so the coupled-zero cross-term drops out</td></tr><tr><td style="text-align:right;">Ordered-beta</td><td style="text-align:center;">✅</td><td style="text-align:right;">proportions / cover with point masses at 0 and 1; <code>fit_ordered_beta_gllvm</code></td></tr><tr><td style="text-align:right;">Beta-hurdle</td><td style="text-align:center;">✅</td><td style="text-align:right;">occurrence Bernoulli × positive Beta; <code>fit_beta_hurdle_gllvm</code></td></tr><tr><td style="text-align:right;">Exponential</td><td style="text-align:center;">✅</td><td style="text-align:right;">positive continuous, <code>Var = μ²</code> (Gamma with shape α=1)</td></tr><tr><td style="text-align:right;">Tweedie</td><td style="text-align:center;">✅</td><td style="text-align:right;">compound Poisson–Gamma (1&lt;p&lt;2); <code>fit_tweedie_gllvm</code>, Dunn–Smyth density series</td></tr></tbody></table><h2 id="Model-structure" tabindex="-1">Model structure <a class="header-anchor" href="#Model-structure" aria-label="Permalink to &quot;Model structure {#Model-structure}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Latent-variable ordination (loadings)</td><td style="text-align:center;">✅</td><td style="text-align:right;">any <code>K</code>; canonical SVD rotation</td></tr><tr><td style="text-align:right;">Fixed-effect covariates (<code>Xβ</code>)</td><td style="text-align:center;">✅ Gaussian · ✅ non-Gaussian (GLM families)</td><td style="text-align:right;"><code>fit_gllvm_cov(Y; family, X, K)</code> adds an <code>Xβ</code> offset to the Laplace path (Poisson/NB/Binomial/Beta/Gamma); shared coefficients over the <code>(p,n,q)</code> design</td></tr><tr><td style="text-align:right;">Between / within (multilevel)</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;"><code>K_W</code> + per-trait diagonal</td></tr><tr><td style="text-align:right;">Phylogenetic random effect</td><td style="text-align:center;">✅ ⚡</td><td style="text-align:right;">fast <strong>O(p)</strong> sparse path, benchmarked to p = 10⁴</td></tr><tr><td style="text-align:right;">Animal model (relatedness / GRM)</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;"><code>relatedness_cov</code>, via the <code>Σ_phy</code> input</td></tr><tr><td style="text-align:right;">Spatial (Matérn / exponential)</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;"><code>spatial_cov</code>, via the <code>Σ_phy</code> input</td></tr><tr><td style="text-align:right;">Structured dependence × non-Gaussian</td><td style="text-align:center;">✅ phylo · 🔨 spatial-latent / animal</td><td style="text-align:right;">phylogenetic GLM landed (<code>fit_phylo_glm</code>, augmented-state joint Laplace); SPDE / Matérn spatial latent field (<code>fit_spde_latent_gllvm</code>) for the non-Gaussian GLLVM</td></tr><tr><td style="text-align:right;">Random slopes <code>(1 + x | g)</code></td><td style="text-align:center;">🔨</td><td style="text-align:right;">formula front-end (c)</td></tr></tbody></table><h2 id="Post-fit-and-inference" tabindex="-1">Post-fit &amp; inference <a class="header-anchor" href="#Post-fit-and-inference" aria-label="Permalink to &quot;Post-fit &amp; inference {#Post-fit-and-inference}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>getLV</code> / <code>getLoadings</code> / <code>rotation</code></td><td style="text-align:center;">✅</td><td style="text-align:right;">all families</td></tr><tr><td style="text-align:right;"><code>predict</code> / <code>fitted</code></td><td style="text-align:center;">✅</td><td style="text-align:right;">all families (ordinal adds <code>:prob</code> / <code>:class</code>)</td></tr><tr><td style="text-align:right;"><code>residuals</code> (Dunn–Smyth + Pearson)</td><td style="text-align:center;">✅</td><td style="text-align:right;">all families</td></tr><tr><td style="text-align:right;"><code>simulate</code> (parametric draw from a fit)</td><td style="text-align:center;">✅ non-Gaussian</td><td style="text-align:right;"><code>simulate(fit, n)</code> / <code>simulate(fit, X)</code> for the GLM + covariate fits</td></tr><tr><td style="text-align:right;"><code>aic</code> / <code>bic</code> / <code>show</code></td><td style="text-align:center;">✅</td><td style="text-align:right;">all families</td></tr><tr><td style="text-align:right;">Σ_y / communality / correlation / phylo signal H²</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;">report-ready extractors</td></tr><tr><td style="text-align:right;">Confidence intervals (Wald / profile / bootstrap)</td><td style="text-align:center;">✅ all families</td><td style="text-align:right;">Gaussian, the GLM families, the two-part families, and ordinal via <code>confint(fit, Y; method=…)</code>; bootstrap is thread-parallel</td></tr><tr><td style="text-align:right;">Ordination biplot</td><td style="text-align:center;">✅</td><td style="text-align:right;"></td></tr></tbody></table><h2 id="Interface" tabindex="-1">Interface <a class="header-anchor" href="#Interface" aria-label="Permalink to &quot;Interface {#Interface}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Matrix-level fit API</td><td style="text-align:center;">✅</td><td style="text-align:right;"><code>fit_gllvm(Y; family, K, …)</code></td></tr><tr><td style="text-align:right;"><code>@formula</code> front-end</td><td style="text-align:center;">✅ fixed effects (wide + long) · 🔨 rest</td><td style="text-align:right;"><code>gllvm(@formula(y ~ 1 + x), Y, data; …)</code> and <code>gllvm(@formula(y ~ 1 + x), long; species, site, …)</code>; random slopes, <code>traits()</code>/<code>phylo()</code>, categoricals deferred</td></tr><tr><td style="text-align:right;"><code>traits()</code> / <code>phylo()</code> formula terms · random slopes <code>(1+x|g)</code></td><td style="text-align:center;">🔨</td><td style="text-align:right;">custom StatsModels terms + RE substrate (design spec&#39;d)</td></tr></tbody></table><h2 id="Performance-—-the-differentiator" tabindex="-1">Performance — the differentiator <a class="header-anchor" href="#Performance-—-the-differentiator" aria-label="Permalink to &quot;Performance — the differentiator {#Performance-—-the-differentiator}&quot;">​</a></h2><p>⚡ ~340× per-fit median speedup over R <code>gllvmTMB</code> on the Gaussian + phylogenetic path (with machine-precision agreement on estimates and likelihoods), and an O(p) phylogenetic gradient benchmarked to p = 10,000. The non-Gaussian and phylogenetic fitters use finite-difference outer gradients (the sparse-Cholesky / CHOLMOD marginals are not generic-AD-friendly); the VA estimator adds analytic inner and envelope-theorem outer gradients for further fit-time gains.</p><h2 id="Honest-gaps" tabindex="-1">Honest gaps <a class="header-anchor" href="#Honest-gaps" aria-label="Permalink to &quot;Honest gaps {#Honest-gaps}&quot;">​</a></h2><p>What&#39;s <strong>done</strong>: every response family — including Tweedie, ordered-beta, beta-hurdle, and ZIB; fixed-effect covariates (<code>Xβ</code>) and species-specific coefficients for the non-Gaussian families; the VA estimator; the ordination trio; the SPDE spatial latent field and the phylogenetic GLM; and confidence intervals (Wald / profile / parametric bootstrap) for every family.</p><p>The remaining gaps are each scoped by an execution-ready spec in <code>docs/superpowers/specs/</code> (design + slice plan + verifiable goals), so they can be built <em>with</em> validation rather than shipped unverified:</p><ul><li><p><strong>Structured dependence × non-Gaussian (animal / spatial extensions)</strong> — the phylogenetic GLM has landed (<code>fit_phylo_glm</code>, an augmented-state joint Laplace), and the SPDE / Matérn spatial latent field is wired into the non-Gaussian GLLVM (<code>fit_spde_latent_gllvm</code>). The remaining work is the general dense-<code>S_u</code> species random effect <code>u ~ N(0, σ²Σ)</code> shared across sites and the scalable large-<code>p</code> determinant. Spec: <code>2026-05-31-nongaussian-structured-dependence-design.md</code>.</p></li><li><p><strong><code>@formula</code> front-end</strong> — <strong>v1 landed</strong>: <code>gllvm(@formula(y ~ 1 + covariates), Y, data; family, K)</code> for continuous fixed effects over wide data routes to the engine (StatsModels + Tables added). Still deferred (design spec&#39;d in <code>2026-05-31-formula-frontend-random-slopes-design.md</code>): long-format data, the <code>traits()</code>/<code>phylo()</code>/<code>latent()</code> custom terms, categorical covariates, and the headline random slopes <code>(1 + x | g)</code> (which need the new RE engine substrate).</p></li><li><p><strong>R bridge (<code>engine = &quot;julia&quot;</code>)</strong> — deferred (post-v1.0); depends on the <code>@formula</code> front-end.</p></li></ul>',17)])])}const p=e(l,[["render",r]]);export{y as __pageData,p as default};
